mapper.select:
SELECT banner_id, banner_badge, banner_title, banner_content, banner_img
FROM banner
WHERE banner_id = #{bannerId}

mapper.update:
UPDATE banner
SET banner_badge = #{bannerBadge},
    banner_title = #{bannerTitle},
    banner_content = #{bannerContent},
    banner_img = #{bannerImg}
WHERE banner_id = #{bannerId}
